}

.ambox-style {
	/* @noflip */
	border-left: 10px solid #fc3;       /* Yellow */
}

.ambox-move {
	/* @noflip */
	border-left: 10px solid #9932cc;    /* Purple */
}

.ambox-protection {
	/* @noflip */
	border-left: 10px solid #a2a9b1;    /* Gray-gold */
}

.ambox .mbox-text {
	border: none;
	/* @noflip */
	padding: 0.25em 0.5em;
	width: 100%;
}

.ambox .mbox-image {
	border: none;
	/* @noflip */
	padding: 2px 0 2px 0.5em;
	text-align: center;
}

.ambox .mbox-imageright {
	border: none;
	/* @noflip */
	padding: 2px 0.5em 2px 0;
